function isSpatial(msg: string): boolean {
  const s = msg.toLowerCase();
  return (
    s.includes("can not reach the destination") ||
    s.includes("destination is in your space")
  );
}

function hasRequest(plan: string): boolean {
  return /request\s*\(\s*['"]/.test(plan);
}

function chefRequestsFromFrame(f: Frame | undefined): string[] {
  if (!f) return [];
  const out: string[] = [];
  for (const t of f.turns) {
    if (t.agent === 0 && hasRequest(t.plan)) {
      const m = t.plan.match(/request\s*\(\s*['"]([^'"]+)['"]\s*\)/g);
      if (m) out.push(...m);
    }
  }
  return out;
}

function joinActions(xs: string[] | undefined): string {
  if (!xs || !xs.length) return "(none)";
  return xs.map((s) => s.trim()).filter(Boolean).join("; ");
}

function frameHasError(f: Frame): boolean {
  return (
    f.error[0].format_num + f.error[0].val_num + f.error[1].format_num + f.error[1].val_num >
    0
  );
}

function summarizeExperiment(exp: Experiment) {
  let spatial = 0;
  let deleg = 0;
  let errs = 0;
  for (let i = 0; i < exp.frames.length; i++) {
    const f = exp.frames[i];
    const prev = exp.frames[i - 1];
    for (const a of [0, 1] as const) {
      const e = f.error[a];
      const n = e.format_num + e.val_num;
      if (n) errs += 1;
      for (const m of e.val_msgs) {
        if (isSpatial(m)) spatial += 1;
      }
      if (a === 1 && n && chefRequestsFromFrame(prev).length) deleg += 1;
    }
  }
  return { spatial, deleg, errs };
}

export default function OvercookedReplayCanvas() {
  const { tokens: t } = useHostTheme();
  const [expIdx, setExpIdx] = useCanvasState("expIdx", 0);
  const [tick, setTick] = useCanvasState("tick", 0);
  const [playing, setPlaying] = useCanvasState("playing", false);
  const intervalRef = useRef<ReturnType<typeof setInterval> | null>(null);

  const exp = EMBEDDED.experiments[expIdx];
  const maxT = exp.frames.length - 1;
  const f = exp.frames[Math.min(tick, maxT)];

  const stats = useMemo(() => summarizeExperiment(exp), [exp]);

  useEffect(() => {
    if (!playing) {
      if (intervalRef.current) {
        clearInterval(intervalRef.current);
        intervalRef.current = null;
      }
      return;
    }
    intervalRef.current = setInterval(() => {
      setTick((prev: number) => {
        const next = prev + 1;
        if (next > maxT) {
          setPlaying(false);
          return maxT;
        }
        return next;
      });
    }, 650);
    return () => {
      if (intervalRef.current) clearInterval(intervalRef.current);
      intervalRef.current = null;
    };
  }, [playing, maxT, setTick, setPlaying, expIdx]);

  const heat = useMemo(() => {
    return exp.frames.map((fr, i) => ({
      i,
      err: frameHasError(fr),
    }));
  }, [exp]);

  const errorPanels = useMemo(() => {
    const rows: { agent: number; failed: string; msgs: string[]; corrected: string; spatial: boolean; deleg: boolean }[] = [];
    const prev = exp.frames[tick - 1];
    const reqs = chefRequestsFromFrame(prev);
    for (const a of [0, 1] as const) {
      const e = f.error[a];
      if (!e.format_num && !e.val_num) continue;
      const msgs = [...e.format_msgs, ...e.val_msgs].map((x) => x.trim());
      const spatial = msgs.some(isSpatial);
      const deleg = a === 1 && reqs.length > 0 && (e.val_num > 0 || e.format_num > 0);
      const failed =
        f.failed_action_hint[a] ||
        (prev ? joinActions(prev.action_list[a]) : "(unknown)");
      const corrected = joinActions(f.action_list[a]);
      rows.push({ agent: a, failed, msgs, corrected, spatial, deleg });
    }
    return rows;
  }, [f, exp.frames, tick]);

  return (
    <Stack gap={16} style={{ padding: 12, maxWidth: 980 }}>
      <H1>Collab-Overcooked replay</H1>
      <Text tone="secondary" size="small">
        Step through logged episodes: kitchen map, actions, dialogue, and validator errors with correction context.
      </Text>
      <Grid columns={6} gap={12}>
        <Stat value={String(exp.frames.length)} label="Timesteps" />
        <Stat value={String(exp.total_score ?? "—")} label="Final score" />
        <Stat value={String(exp.total_order_finished.length)} label="Orders done" />
        <Stat value={String(stats.errs)} label="Agent error events" tone="warning" />
        <Stat value={String(stats.spatial)} label="Spatial msgs" tone="warning" />
        <Stat value={String(stats.deleg)} label="Deleg. + asst. err" tone="danger" />
      </Grid>
      <Row gap={8} wrap>
        {EMBEDDED.experiments.map((e, i) => (
          <Pill key={e.id} active={i === expIdx} onClick={() => { setExpIdx(i); setTick(0); setPlaying(false); }}>
            {e.label}
          </Pill>
        ))}
      </Row>
      <Divider />
      <Row gap={8} align="center" wrap>
        <Button variant="secondary" onClick={() => setTick((x: number) => Math.max(0, x - 1))} disabled={tick <= 0}>
          Step back
        </Button>
        <Button variant="primary" onClick={() => setPlaying((p: boolean) => !p)}>
          {playing ? "Pause" : "Play"}
        </Button>
        <Button variant="secondary" onClick={() => setTick((x: number) => Math.min(maxT, x + 1))} disabled={tick >= maxT}>
          Step forward
        </Button>
        <Button variant="ghost" onClick={() => { setTick(0); setPlaying(false); }}>
          Reset
        </Button>
        <Spacer />
        <Text weight="semibold">
          t={f.timestamp} / {maxT}
        </Text>
      </Row>
      <Row gap={2} wrap style={{ alignItems: "stretch" }}>
        {heat.map((h) => (
          <button
            key={h.i}
            type="button"
            title={`t=${h.i}`}
            onClick={() => { setTick(h.i); setPlaying(false); }}
            style={{
              width: 6,
              height: 14,
              border: "none",
              padding: 0,
              cursor: "pointer",
              background: h.err ? t.fill.quaternary : t.fill.secondary,
              outline: h.i === tick ? `2px solid ${t.accent.primary}` : "none",
            }}
          />
        ))}
      </Row>
      <Grid columns="1fr 1.1fr" gap={16}>
        <Stack gap={10}>
          <H2>Kitchen</H2>
          <pre
            style={{
              margin: 0,
              padding: 12,
              fontFamily: "ui-monospace, SFMono-Regular, Menlo, Monaco, monospace",
              fontSize: 11,
              lineHeight: 1.35,
              whiteSpace: "pre",
              background: t.bg.elevated,
              color: t.text.primary,
              border: `1px solid ${t.stroke.secondary}`,
              borderRadius: 6,
              overflow: "auto",
            }}
          >
            {f.map}
          </pre>
          <Row gap={8} align="center" wrap>
            <Text tone="secondary" size="small">
              Orders
            </Text>
            {f.order_list.map((o) => (
              <Pill key={o} size="sm">
                {o}
              </Pill>
            ))}
            <Text tone="secondary" size="small">
              Score {f.score}
            </Text>
          </Row>
        </Stack>
        <Stack gap={12}>
          <H2>Agents</H2>
          <Stack gap={8}>
            <H3>Actions this timestep</H3>
            <Row gap={12} wrap>
              <Stack gap={4}>
                <Text size="small" tone="secondary">
                  Chef
                </Text>
                <Pill tone="neutral">{f.actions[0] || "(none)"}</Pill>
              </Stack>
              <Stack gap={4}>
                <Text size="small" tone="secondary">
                  Assistant
                </Text>
                <Pill tone="neutral">{f.actions[1] || "(none)"}</Pill>
              </Stack>
            </Row>
          </Stack>
          <Stack gap={8}>
            <H3>Dialogue</H3>
            {f.turns.length === 0 ? (
              <Text tone="tertiary" size="small">
                No dialogue this timestep.
              </Text>
            ) : (
              <Stack gap={6}>
                {f.turns.map((tr, idx) => {
                  const chef = tr.agent === 0;
                  const say = (tr.say || "").trim();
                  const muted = !say || say.toUpperCase() === "[NOTHING]";
                  return (
                    <div
                      key={idx}
                      style={{
                        alignSelf: chef ? "flex-start" : "flex-end",
                        maxWidth: "92%",
                        padding: "8px 10px",
                        borderRadius: 6,
                        background: chef ? t.fill.secondary : t.fill.tertiary,
                        border: `1px solid ${t.stroke.tertiary}`,
                      }}
                    >
                      <Text size="small" weight="semibold">
                        {chef ? "Chef" : "Assistant"}
                      </Text>
                      <Text size="small" tone={muted ? "tertiary" : "primary"}>
                        {muted ? "(nothing said)" : say}
                      </Text>
                    </div>
                  );
                })}
              </Stack>
            )}
          </Stack>
          <Card collapsible defaultOpen={false}>
            <CardHeader trailing={<Text size="small">Plans</Text>}>Details</CardHeader>
            <CardBody>
              <Stack gap={8}>
                {f.turns.map((tr, idx) => (
                  <Stack key={idx} gap={4}>
                    <Text size="small" weight="semibold">
                      {tr.agent === 0 ? "Chef" : "Assistant"} plan
                    </Text>
                    <Code>{tr.plan || "(none)"}</Code>
                  </Stack>
                ))}
                {f.turns.length === 0 ? <Text tone="tertiary" size="small">No plan entries.</Text> : null}
              </Stack>
            </CardBody>
          </Card>
          {errorPanels.length ? (
            <Stack gap={10}>
              <H3>Error and correction</H3>
              {errorPanels.map((row) => (
                <Card key={row.agent} variant="default">
                  <CardHeader>{row.agent === 0 ? "Chef" : "Assistant"}</CardHeader>
                  <CardBody>
                    <Row gap={8} style={{ marginBottom: 10 }} wrap>
                      {row.spatial ? (
                        <Pill size="sm" tone="warning">
                          Spatial violation
                        </Pill>
                      ) : null}
                      {row.deleg ? (
                        <Pill size="sm" tone="deleted">
                          Invalid delegation
                        </Pill>
                      ) : null}
                    </Row>
                    <Grid columns="1fr 1fr" gap={12}>
                      <Stack gap={6}>
                        <Text size="small" weight="semibold">
                          Failed / rejected
                        </Text>
                        <Code>{row.failed}</Code>
                        {row.msgs.map((m, i) => (
                          <Text key={i} size="small" tone="secondary">
                            {m}
                          </Text>
                        ))}
                      </Stack>
                      <Stack gap={6}>
                        <Text size="small" weight="semibold">
                          Corrected plan (this step)
                        </Text>
                        <Code>{row.corrected}</Code>
                        <Text size="small" tone="primary">
                          Executed after validation / retry.
                        </Text>
                      </Stack>
                    </Grid>
                  </CardBody>
                </Card>
              ))}
            </Stack>
          ) : null}
        </Stack>
      </Grid>
    </Stack>
  );
}
